import{_ as r,o as i,c as t,a2 as a}from"./chunks/framework.Cuq8tsM6.js";const v=JSON.parse('{"title":"1. Brief Annonceur","description":"","frontmatter":{"title":"1. Brief Annonceur"},"headers":[],"relativePath":"docs/fr/advertisers/dedicated-email/1-brief-annonceur.md","filePath":"docs/fr/advertisers/dedicated-email/1-brief-annonceur.md"}'),o={name:"docs/fr/advertisers/dedicated-email/1-brief-annonceur.md"};function s(d,e,n,l,p,u){return i(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="etape-1-le-brief-annonceur" tabindex="-1">Étape 1 : Le Brief Annonceur <a class="header-anchor" href="#etape-1-le-brief-annonceur" aria-label="Permalink to &quot;Étape 1 : Le Brief Annonceur&quot;">​</a></h1><p>Votre rôle : fournir la &quot;matière première&quot; qui permettra au Distributeur de construire un email performant.</p><hr><h2>Remplir le formulaire</h2><div style="background-color:var(--vp-c-bg-soft);border:1px solid var(--vp-c-divider);border-radius:8px;padding:30px;text-align:center;margin-bottom:40px;"><p>Toute campagne débute par la soumission du brief via notre formulaire dédié.</p><a href="https://tally.so/r/9qN9WY" target="_blank" class="btn btn-primary">👉 Accéder au Brief (Tally)</a></div><h2>Ce que vous devez fournir</h2><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(250px, 1fr));gap:20px;"><div style="border:1px solid var(--vp-c-divider);border-radius:6px;padding:20px;"><div style="font-size:30px;margin-bottom:10px;">🎁</div><h3>L&#39;Offre</h3><p>Quelle est la promesse ? (ex: &quot;20€ offerts dès 100€ d&#39;achat&quot;). Soyez clair et incitatif.</p></div><div style="border:1px solid var(--vp-c-divider);border-radius:6px;padding:20px;"><div style="font-size:30px;margin-bottom:10px;">🖼️</div><h3>Les Visuels</h3><p>Logos (vectoriel ou HD), packshots produits sur fond blanc, visuels d&#39;ambiance.</p></div><div style="border:1px solid var(--vp-c-divider);border-radius:6px;padding:20px;"><div style="font-size:30px;margin-bottom:10px;">✍️</div><h3>Le Wording</h3><p>Les arguments clés (USP), le ton de la marque, et les mots-clés obligatoires.</p></div><div style="border:1px solid var(--vp-c-divider);border-radius:6px;padding:20px;"><div style="font-size:30px;margin-bottom:10px;">🔗</div><h3>Les Liens</h3><p>Les URLs de destination (Landing pages) vers lesquelles rediriger le trafic.</p></div></div><div class="bg-yellow-000" style="border-color:var(--gi-tint-yellow-text);"><h4>💡 Conseil Pro</h4><p>Ne cherchez pas à imposer une charte graphique stricte. Laissez le Distributeur adapter vos visuels à son univers : c&#39;est lui qui connaît le mieux ce qui fait réagir sa communauté.</p></div><p class="text-grey-lt-000">Une fois le brief envoyé, l&#39;équipe getinside configure la campagne et notifie le Distributeur qu&#39;il peut démarrer la création.</p>',9)])])}const f=r(o,[["render",s]]);export{v as __pageData,f as default};
